import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import DropshippingExpandedContent, { DROPSHIPPING_EXPANDED_FAQS } from "@/components/DropshippingExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}


const FAQS = [
  { q: "How do I calculate profit after a discount?", a: "Discounted price = Original price  x  (1 - discount%). Profit = Discounted price - Cost. For example: $100 original, 20% off = $80 sale price. If cost is $40, profit = $40." },
  { q: "What's the maximum safe discount to still break even?", a: "Your maximum discount is determined by: Max Discount % = ((Original Price - Cost) / Original Price)  x  100. Any discount beyond that means you're selling at a loss." },
  { q: "Why do discounts hurt margins more than they seem?", a: "A 20% price discount on a product with a 40% margin reduces your profit by 50% - not 20%. Margins are disproportionately affected by discounts, especially on tight-margin products." },
  { q: "How should I use discounts strategically?", a: "Limit discounts to clear inventory, acquire first-time customers, or hit volume thresholds. Bundle products instead of discounting single items to maintain per-unit margin while offering perceived value." },
  { q: "What is the maximum discount I can offer without losing money?", a: "Maximum break-even discount = ((Selling Price - Cost)  x  Selling Price)  x  100. For a $100 product with $40 cost, the max discount is 60%. At 60% off, the sale price equals $40, which exactly covers cost." },
  { q: "How do discounts affect customer perception of value?", a: "Research shows discounts can increase conversions but may also signal lower quality. Products with frequent large discounts (50%+) often lose perceived value. Occasional targeted discounts (15-25%) to specific segments work better than blanket storewide sales." },
  { q: "Should I offer percentage discounts or dollar-off discounts?", a: "Use percentage discounts for high-ticket items (20% off $200 sounds larger than $40 off). Use dollar-off discounts for low-ticket items ($5 off sounds larger than 5% off on a $100 item). This is known as the Rule of 100." },
];

const EXPANDED_FAQS = DROPSHIPPING_EXPANDED_FAQS.discount;

export default function DiscountProfitCalculator() {
  useCurrencyVersion();
  const [originalPrice, setOriginalPrice] = useState(100);
  const [discountPct, setDiscountPct] = useState(20);
  const [cost, setCost] = useState(40);

  const discountedPrice = originalPrice * (1 - discountPct / 100);
  const profit = discountedPrice - cost;
  const margin = discountedPrice > 0 ? (profit / discountedPrice) * 100 : 0;
  const originalMargin = originalPrice > 0 ? ((originalPrice - cost) / originalPrice) * 100 : 0;
  const savings = originalPrice - discountedPrice;
  const isPos = profit >= 0;
  const maxDiscount = originalPrice > 0 ? ((originalPrice - cost) / originalPrice) * 100 : 0;

  return (
    <>
      <SEOHead
        title="Free Discount Profit Calculator Online - Know Your Margins Before Any Sale | CalcHive"
        description="Free online discount profit calculator. Calculate your exact profit and margin after applying any discount before you run a sale. 100% free, instant results, no account needed."
        canonical="/discount-profit-calculator"
        keywords="free discount profit calculator, profit after discount calculator free, discount margin calculator free online, sale profit calculator free, calculate profit with discount free"
        category="Dropshipping"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/50 px-3 py-1 rounded-full mb-4">Dropshipping</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Discount Profit Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free discount profit calculator to calculate your profit and profit margin after applying a discount to any product. Enter the original price, discount percentage, and product cost to see your sale price, final profit, remaining margin, and the maximum discount you can offer before breaking even. It works as a profit after discount calculator free, a discount margin calculator free online, a sale profit calculator free, and a way to calculate profit with discount free before any promotion.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="original-price" label="Original Price" value={originalPrice} min={1} max={2000} step={1} onChange={setOriginalPrice} format={fmt} testId="input-original-price" />
            <SliderInput id="discount-pct" label="Discount" value={discountPct} min={0} max={90} step={1} onChange={setDiscountPct} format={v => `${v}%`} testId="input-discount" />
            <SliderInput id="product-cost-d" label="Product Cost" value={cost} min={0} max={1000} step={1} onChange={setCost} format={fmt} testId="input-cost" />
          </div>
          <motion.div key={`${originalPrice}-${discountPct}-${cost}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`rounded-2xl p-6 mb-4 text-center shadow-lg ${isPos ? "bg-gradient-to-br from-emerald-500 to-emerald-700" : "bg-gradient-to-br from-red-500 to-red-700"}`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final Profit</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-profit">{fmt(profit)}</p>
              <p className="text-white/70 text-sm mt-1">{margin.toFixed(1)}% margin after {discountPct}% discount</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Sale Price", value: fmt(discountedPrice), testId: "result-sale-price" },
                { label: "Customer Saves", value: fmt(savings) },
                { label: "Profit Margin", value: `${margin.toFixed(1)}%` },
              ].map(({ label, value, testId }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground" data-testid={testId}>{value}</p>
                </div>
              ))}
            </div>
            <div className="mt-3 p-3 bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-800 rounded-xl text-sm text-amber-700 dark:text-amber-400 text-center">
              Maximum safe discount: <strong>{maxDiscount.toFixed(1)}%</strong> - any more and you sell at a loss
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Calculate Your Profit After Discount for Free</h2>
          <p className="text-muted-foreground leading-relaxed">A discount reduces your selling price, but your cost stays the same. This means the discount comes directly out of your profit - not out of your cost. This makes discounts much more damaging to margins than they appear.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Sale Price = Original Price  x  (1 - Discount%)</p>
            <p>Profit = Sale Price - Cost</p>
            <p>Margin = (Profit  x  Sale Price)  x  100</p>
            <p>Max Discount (break-even) = ((Price - Cost)  x  Price)  x  100</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Know Your Margins Before Running a Sale</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Original Margin", "10% Discount", "20% Discount", "30% Discount", "40% Discount"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  [20, "8%", "0%", "LOSS", "LOSS"],
                  [30, "18%", "7%", "0%", "LOSS"],
                  [40, "28%", "17%", "5%", "LOSS"],
                  [50, "39%", "28%", "17%", "0%"],
                  [60, "50%", "40%", "29%", "17%"],
                ].map(([margin, ...discounts]) => (
                  <tr key={margin} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{margin}%</td>
                    {discounts.map((d, i) => (
                      <td key={i} className={`py-2.5 px-3 font-medium ${String(d).includes("LOSS") ? "text-red-600 dark:text-red-400" : "text-muted-foreground"}`}>{d}</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Discount Margin Tool for Store Owners and Dropshippers</h2>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">Bundle deals:</strong> Pair two products for a combined discount. The perceived value is higher while per-unit margin remains intact.</li>
            <li><strong className="text-foreground">Volume discounts:</strong> Offer discounts only for larger quantities (e.g., buy 3, save 15%). This increases order value while preserving margin on single-unit sales.</li>
            <li><strong className="text-foreground">Time-limited urgency:</strong> A 24-hour flash sale creates urgency without training customers to wait for regular sales.</li>
            <li><strong className="text-foreground">Loyalty rewards:</strong> Reward repeat customers with exclusive discounts rather than publishing sale prices publicly.</li>
          </ul>
        </section>

        <DropshippingExpandedContent kind="discount" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/discount-profit-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


